import sys

class Solution:
    def convertInfixToPrefix(self, infix: str) -> str:
        precedence = {'+': 1, '-': 1, '*': 2, '/': 2, '^': 3}
        stack = []
        prefix = ''
        infix = infix.replace(' ', '')
        for char in infix[::-1]:
            if char.isalnum():
                prefix = char + prefix
            elif char == ')':
                stack.append(char)
            elif char == '(':
                while stack and stack[-1] != ')':
                    prefix = stack.pop() + prefix
                stack.pop()
            else:
                while stack and stack[-1] in precedence and precedence[stack[-1]] > precedence[char]:
                    prefix = stack.pop() + prefix
                stack.append(char)
        while stack:
            prefix = stack.pop() + prefix
        return prefix

