#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string convertInfixToPrefix(string infix) {
        unordered_map<char, int> precedence = {{'+', 1}, {'-', 1}, {'*', 2}, {'/', 2}, {'^', 3}};
        stack<char> st;
        string prefix;
        for (int i = infix.size() - 1; i >= 0; --i) {
            char c = infix[i];
            if (isalnum(c)) {
                prefix = c + prefix;
            } else if (c == ')') {
                st.push(c);
            } else if (c == '(') {
                while (!st.empty() && st.top() != ')') {
                    prefix = st.top() + prefix;
                    st.pop();
                }
                if (!st.empty()) {
                    st.pop();
                }
            } else {
                while (!st.empty() && precedence.find(st.top()) != precedence.end() && precedence[st.top()] > precedence[c]) {
                    prefix = st.top() + prefix;
                    st.pop();
                }
                st.push(c);
            }
        }
        while (!st.empty()) {
            prefix = st.top() + prefix;
            st.pop();
        }
        return prefix;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    string infix;
    cin >> infix;
    Solution sol;
    string ans = sol.convertInfixToPrefix(infix);
    cout << ans << '\n';
    return 0;
}
